package co.edu.elecciones.service; import co.edu.elecciones.repository.*; import com.lowagie.text.*; import com.lowagie.text.pdf.PdfWriter; import org.springframework.stereotype.Service; import java.io.*; import java.nio.charset.StandardCharsets;
@Service public class ReportService { private final OfficialResultRepository results; public ReportService(OfficialResultRepository r){results=r;} public byte[] csv(){ StringBuilder sb=new StringBuilder("id,candidato,partido,departamento,municipio,votos,porcentaje,mesas_reportadas,origen\n"); for(var r:results.findAll()) sb.append(r.id).append(',').append(r.candidate.name).append(',').append(r.candidate.party.acronym).append(',').append(r.department).append(',').append(r.municipality).append(',').append(r.votes).append(',').append(r.percentage).append(',').append(r.reportedTables).append(',').append(r.source).append('\n'); return sb.toString().getBytes(StandardCharsets.UTF_8);} public byte[] pdf(){ try(ByteArrayOutputStream out=new ByteArrayOutputStream()){ Document d=new Document(); PdfWriter.getInstance(d,out); d.open(); d.add(new Paragraph("Reporte de resultados consolidados")); d.add(new Paragraph("Predicción ≠ resultado oficial")); for(var r:results.findAll()) d.add(new Paragraph(r.candidate.name+" - "+r.department+" - votos: "+r.votes)); d.close(); return out.toByteArray(); } catch(Exception e){ throw new RuntimeException(e);} } }
